  1	import React, { FC, useEffect, useMemo, useRef, useState } from 'react';
  2	import classNames from 'classnames';
  3	
  4	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
  5	import RedHatInstanceTypeSeriesSizesMenuItems from '@kubevirt-utils/components/AddBootableVolumeModal/components/VolumeMetadata/components/InstanceTypeDrilldownSelect/components/RedHatInstanceTypeSeriesMenu/RedHatInstanceTypeSeriesSizesMenuItem';
  6	import { instanceTypeSeriesNameMapper } from '@kubevirt-utils/components/AddBootableVolumeModal/components/VolumeMetadata/components/InstanceTypeDrilldownSelect/utils/constants';
  7	import { RedHatInstanceTypeSeries } from '@kubevirt-utils/components/AddBootableVolumeModal/components/VolumeMetadata/components/InstanceTypeDrilldownSelect/utils/types';
  8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  9	import { readableSizeUnit } from '@kubevirt-utils/utils/units';
 10	import {
 11	  Card,
 12	  CardBody,
 13	  Menu,
 14	  MenuContent,
 15	  MenuList,
 16	  MenuToggle,
 17	  Popper,
 18	  Tooltip,
 19	} from '@patternfly/react-core';
 20	import { AngleDownIcon } from '@patternfly/react-icons';
 21	
 22	import { UseInstanceTypeCardMenuSectionValues } from '../../../../utils/types';
 23	
 24	import './RedHatSeriesMenuCard.scss';
 25	
 26	type RedHatSeriesMenuCardProps = {
 27	  rhSeriesItem: RedHatInstanceTypeSeries;
 28	} & UseInstanceTypeCardMenuSectionValues;
 29	
 30	const RedHatSeriesMenuCard: FC<RedHatSeriesMenuCardProps> = ({
 31	  activeMenu,
 32	  menuRef,
 33	  onMenuSelect,
 34	  onMenuToggle,
 35	  rhSeriesItem,
 36	}) => {
 37	  const { t } = useKubevirtTranslation();
 38	
 39	  const [distance, setDistance] = useState(0);
 40	  const cardRef = useRef<HTMLDivElement>(null);
 41	  const toggleRef = useRef<HTMLDivElement>(null);
 42	  const {
 43	    instanceTypeVMState: { selectedInstanceType },
 44	  } = useInstanceTypeVMStore();
 45	
 46	  const { classAnnotation, classDisplayNameAnnotation, descriptionAnnotation, seriesName, sizes } =
 47	    rhSeriesItem;
 48	
 49	  const { Icon, seriesLabel } = instanceTypeSeriesNameMapper[seriesName] || {};
 50	
 51	  const isMenuExpanded = useMemo(() => seriesName === activeMenu, [activeMenu, seriesName]);
 52	  const isSelectedMenu = useMemo(
 53	    () => selectedInstanceType?.name?.startsWith(seriesName),
 54	    [selectedInstanceType, seriesName],
 55	  );
 56	
 57	  const selectedITLabel = useMemo(() => {
 58	    const itSize = sizes?.find(
 59	      (size) => `${seriesName}.${size.sizeLabel}` === selectedInstanceType?.name,
 60	    );
 61	
 62	    const { cpus, memory, sizeLabel } = itSize || {};
 63	    return t('{{sizeLabel}}: {{cpus}} CPUs, {{memory}} Memory', {
 64	      cpus,
 65	      memory: readableSizeUnit(memory),
 66	      sizeLabel,
 67	    });
 68	  }, [selectedInstanceType, seriesName, sizes, t]);
 69	
 70	  useEffect(() => {
 71	    const calculateDistance = () => {
 72	      if (cardRef.current && toggleRef.current) {
 73	        const cardRect = cardRef.current.getBoundingClientRect();
 74	        const toggleRect = toggleRef.current.getBoundingClientRect();
 75	        setDistance(toggleRect.bottom - cardRect.bottom + 4);
 76	      }
 77	    };
 78	
 79	    calculateDistance();
 80	    window.addEventListener('resize', calculateDistance);
 81	
 82	    return () => {
 83	      window.removeEventListener('resize', calculateDistance);
 84	    };
 85	  }, [cardRef.current, toggleRef.current]);
 86	
 87	  const card = (
 88	    <Card className="instance-type-series-menu-card__toggle-card">
 89	      <div className="instance-type-series-menu-card__card-icon">{Icon && <Icon />}</div>
 90	      <CardBody>
 91	        <div className="instance-type-series-menu-card__card-title">
 92	          {classDisplayNameAnnotation}
 93	        </div>
 94	        <div className="instance-type-series-menu-card__card-toggle-text" ref={toggleRef}>
 95	          {seriesLabel || classAnnotation} <AngleDownIcon />
 96	        </div>
 97	        <div className="instance-type-series-menu-card__card-footer">
 98	          {isSelectedMenu && selectedITLabel}
 99	        </div>
100	      </CardBody>
101	    </Card>
102	  );
103	  return (
104	    <Popper
105	      popper={
106	        <Menu activeMenu={activeMenu} id={seriesName} ref={menuRef}>
107	          <MenuContent>
108	            <MenuList>
109	              <RedHatInstanceTypeSeriesSizesMenuItems
110	                selected={selectedInstanceType?.name}
111	                seriesName={seriesName}
112	                setSelected={onMenuSelect}
113	                sizes={sizes}
114	              />
115	            </MenuList>
116	          </MenuContent>
117	        </Menu>
118	      }
119	      trigger={
120	        <MenuToggle
121	          className={classNames(
122	            'instance-type-series-menu-card__toggle-container',
123	            isSelectedMenu && 'selected',
124	          )}
125	          isExpanded={isMenuExpanded}
126	          onClick={(event) => onMenuToggle(event, seriesName)}
127	          ref={cardRef}
128	          variant="plain"
129	        >
130	          {!isMenuExpanded ? <Tooltip content={descriptionAnnotation}>{card}</Tooltip> : card}
131	        </MenuToggle>
132	      }
133	      direction="down"
134	      distance={distance}
135	      isVisible={isMenuExpanded}
136	    />
137	  );
138	};
139	
140	export default RedHatSeriesMenuCard;

