}
export const QuickStartCatalogFilterCountWrapper: React.FC<
  QuickStartCatalogFilterCountWrapperProps
> = ({ quickStartsCount }) => <QuickStartCatalogFilterCount quickStartsCount={quickStartsCount} />;
