            data-test-id="quick-start-task-subtitle"
          >
            {' '}
            {subtitle}
          </span>
        )}
      </Title>
      {tryAgain}
    </div>
  );

  return (
    <WizardNavItem
      content={content}
      stepIndex={taskIndex}
      onClick={() => onTaskSelect(taskIndex - 1)}
      component="button"
      isCurrent={isActiveTask}
    >
      {children}
    </WizardNavItem>
  );
};

